import { 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  orderBy, 
  deleteDoc,
  serverTimestamp
} from 'firebase/firestore';
import { db } from './firebase';

/**
 * Saves a generated itinerary to Firestore
 */
export const saveItinerary = async (userId, tripData) => {
  if (!userId) throw new Error("User must be authenticated to save trips.");
  
  // We use the trip ID generated by the frontend (or create one)
  const tripId = tripData.id || crypto.randomUUID();
  const tripRef = doc(db, 'users', userId, 'trips', tripId);
  
  const payload = {
    ...tripData,
    id: tripId,
    createdAt: serverTimestamp(),
  };

  await setDoc(tripRef, payload);
  return payload;
};

/**
 * Fetches all saved itineraries for a user
 */
export const getUserItineraries = async (userId) => {
  if (!userId) return [];
  
  const tripsRef = collection(db, 'users', userId, 'trips');
  const q = query(tripsRef, orderBy('createdAt', 'desc'));
  
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => doc.data());
};

/**
 * Deletes an itinerary
 */
export const deleteItinerary = async (userId, tripId) => {
  if (!userId || !tripId) return;
  const tripRef = doc(db, 'users', userId, 'trips', tripId);
  await deleteDoc(tripRef);
};
